# Robust Error Handling

APIs fail. Handle errors gracefully.

## Common API Errors

**Rate Limits (429):**
```python
from anthropic import RateLimitError

try:
    message = client.messages.create(...)
except RateLimitError as e:
    print("Rate limited. Wait and retry.")
```

**Authentication (401):**
```python
from anthropic import AuthenticationError

try:
    message = client.messages.create(...)
except AuthenticationError:
    print("Invalid API key")
```

**Invalid Request (400):**
```python
from anthropic import BadRequestError

try:
    message = client.messages.create(...)
except BadRequestError as e:
    print(f"Invalid request: {e}")
```

## Exponential Backoff

```python
import time
import random

def call_with_backoff(func, max_retries=5):
    for attempt in range(max_retries):
        try:
            return func()
        except RateLimitError:
            if attempt == max_retries - 1:
                raise

            wait_time = (2 ** attempt) + random.uniform(0, 1)
            print(f"Rate limited. Waiting {wait_time:.1f}s...")
            time.sleep(wait_time)

    raise Exception("Max retries exceeded")

def make_request():
    return client.messages.create(
        model="claude-3-5-sonnet-20241022",
        max_tokens=1024,
        messages=[{"role": "user", "content": "Hello"}]
    )

response = call_with_backoff(make_request)
```

## Comprehensive Error Handler

```python
from anthropic import (
    APIError,
    RateLimitError,
    AuthenticationError,
    BadRequestError,
    APIConnectionError,
    APITimeoutError
)
import time
import random

def robust_api_call(prompt, max_retries=3):
    for attempt in range(max_retries):
        try:
            message = client.messages.create(
                model="claude-3-5-sonnet-20241022",
                max_tokens=1024,
                messages=[{"role": "user", "content": prompt}],
                timeout=30.0
            )
            return message.content[0].text

        except RateLimitError:
            if attempt == max_retries - 1:
                raise
            wait_time = (2 ** attempt) + random.uniform(0, 1)
            time.sleep(wait_time)

        except AuthenticationError:
            raise ValueError("Invalid API key")

        except BadRequestError as e:
            raise ValueError(f"Invalid request: {e}")

        except APIConnectionError:
            if attempt == max_retries - 1:
                raise
            time.sleep(2)

        except APITimeoutError:
            if attempt == max_retries - 1:
                raise
            time.sleep(1)

        except APIError as e:
            print(f"API error: {e}")
            raise

    raise Exception("Max retries exceeded")
```

## Circuit Breaker Pattern

```python
from datetime import datetime, timedelta

class CircuitBreaker:
    def __init__(self, failure_threshold=5, timeout=60):
        self.failure_threshold = failure_threshold
        self.timeout = timeout
        self.failures = 0
        self.last_failure_time = None
        self.state = "closed"  # closed, open, half-open

    def call(self, func):
        if self.state == "open":
            if datetime.now() - self.last_failure_time > timedelta(seconds=self.timeout):
                self.state = "half-open"
            else:
                raise Exception("Circuit breaker is open")

        try:
            result = func()
            if self.state == "half-open":
                self.state = "closed"
                self.failures = 0
            return result
        except Exception as e:
            self.failures += 1
            self.last_failure_time = datetime.now()

            if self.failures >= self.failure_threshold:
                self.state = "open"

            raise e

breaker = CircuitBreaker()
response = breaker.call(make_request)
```

## Best Practices

1. Use exponential backoff for rate limits
2. Catch specific exceptions
3. Set reasonable timeouts
4. Log errors for debugging
5. Implement circuit breakers for repeated failures
6. Provide user-friendly error messages
